// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const totalSteps = 5;
  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [submitted, setSubmitted] = useState<boolean>(false);
  const [attemptedNext, setAttemptedNext] = useState<boolean>(false);

  const trimmedName = name.trim();
  const trimmedEmail = email.trim();
  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(trimmedEmail), [trimmedEmail]);
  const nameError = currentStep === 1 && !trimmedName ? 'Name is required.' : '';
  const emailError =
    currentStep === 1 && !trimmedEmail
      ? 'Email is required.'
      : currentStep === 1 && !emailValid
        ? 'Enter a valid email address.'
        : '';

  const satisfactionOptions = useMemo(
    () =>
      (props.satisfactionLabels || []).map((label, index) => ({
        value: String(index + 1),
        label,
      })),
    [props.satisfactionLabels],
  );

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setSelectedFeatures((prev) => {
      if (checked) {
        return prev.includes(feature) ? prev : [...prev, feature];
      }
      return prev.filter((f) => f !== feature);
    });
  }, []);

  const stepValid = useMemo(() => {
    if (currentStep === 1) return Boolean(trimmedName) && Boolean(trimmedEmail) && emailValid;
    if (currentStep === 2) return Boolean(satisfaction);
    if (currentStep === 3) return true;
    if (currentStep === 4) return comments.length <= 500;
    return true;
  }, [currentStep, trimmedName, trimmedEmail, emailValid, satisfaction, comments.length]);

  const nextDisabled = (currentStep === 1 || currentStep === 2 || currentStep === 4) && !stepValid;

  const handleNext = useCallback(() => {
    if (!stepValid) {
      setAttemptedNext(true);
      return;
    }
    setAttemptedNext(false);
    setCurrentStep((prev) => Math.min(totalSteps, prev + 1));
  }, [stepValid, totalSteps]);

  const handleBack = useCallback(() => {
    setAttemptedNext(false);
    setCurrentStep((prev) => Math.max(1, prev - 1));
  }, []);

  const handleSubmit = useCallback(() => {
    if (!trimmedName || !trimmedEmail || !emailValid || !satisfaction) {
      return;
    }
    const payload: ActionSubmitPayload = {
      name: trimmedName,
      email: trimmedEmail,
      satisfaction: Number(satisfaction),
      features: selectedFeatures,
      comments,
    };
    submit(payload);
    setSubmitted(true);
  }, [trimmedName, trimmedEmail, emailValid, satisfaction, selectedFeatures, comments, props]);

  const satisfactionLabel = useMemo(() => {
    const idx = Number(satisfaction) - 1;
    if (idx < 0 || idx >= (props.satisfactionLabels || []).length) return 'Not selected';
    return props.satisfactionLabels[idx];
  }, [satisfaction, props.satisfactionLabels]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Text variant="label" color="var(--ggui-color-onSurface)">
                Step {currentStep} of {totalSteps}
              </Text>
              <Badge variant="primary">
                {Math.round((currentStep / totalSteps) * 100)}%
              </Badge>
            </Row>
            <Progress value={currentStep} max={totalSteps} />
          </Stack>
        </Card>

        {submitted ? (
          <Alert variant="success" title="Survey submitted">
            Thank you! Your responses have been submitted successfully.
          </Alert>
        ) : null}

        <Card padding="var(--ggui-spacing-6)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-6)">
            {currentStep === 1 ? (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Basic Information</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={nameError || undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="Enter your email"
                  error={emailError || undefined}
                />
              </Stack>
            ) : null}

            {currentStep === 2 ? (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction Rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  error={attemptedNext && !satisfaction ? 'Please choose a rating.' : undefined}
                />
              </Stack>
            ) : null}

            {currentStep === 3 ? (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature Interests</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Select all features you are interested in.
                </Text>
                <Stack gap="var(--ggui-spacing-2)">
                  {(props.featureOptions || []).length === 0 ? (
                    <Alert variant="info">No feature options are currently available.</Alert>
                  ) : (
                    (props.featureOptions || []).map((feature) => (
                      <Checkbox
                        key={feature}
                        label={feature}
                        checked={selectedFeatures.includes(feature)}
                        onChange={(checked) => toggleFeature(feature, checked)}
                      />
                    ))
                  )}
                </Stack>
              </Stack>
            ) : null}

            {currentStep === 4 ? (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional Comments</Heading>
                <TextArea
                  label="Comments"
                  value={comments}
                  onChange={setComments}
                  placeholder="Share anything else you'd like us to know"
                  maxLength={500}
                  showCount
                  rows={6}
                  helperText="Optional"
                />
              </Stack>
            ) : null}

            {currentStep === 5 ? (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Final Review</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {trimmedName || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {trimmedEmail || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfactionLabel}</Text>
                    <Text><Text is="span" weight="semibold">Features:</Text> {selectedFeatures.length ? selectedFeatures.join(', ') : 'None selected'}</Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments || 'No comments provided'}</Text>
                  </Stack>
                </Card>
              </Stack>
            ) : null}

            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Button variant="outline" onClick={handleBack} disabled={currentStep === 1}>
                Back
              </Button>
              {currentStep < totalSteps ? (
                <Button variant="primary" onClick={handleNext} disabled={nextDisabled}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit}>
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

