// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const columns = useMemo(
    () => [
      { id: 'todo', name: 'To Do' },
      { id: 'in-progress', name: 'In Progress' },
      { id: 'done', name: 'Done' }
    ],
    []
  );

  const validColumnIds = useMemo(() => columns.map((c) => c.id), [columns]);
  const fallbackColumnId = 'todo';
  const normalizeColumnId = useCallback(
    (columnId?: string) => (columnId && validColumnIds.includes(columnId) ? columnId : fallbackColumnId),
    [validColumnIds]
  );

  const initialTasks = useMemo(
    () =>
      (props.tasks ?? []).map((task, index) => ({
        id: task.id ?? `task-${index}`,
        title: task.title ?? 'Untitled task',
        priority: task.priority ?? 'low',
        assignee: task.assignee ?? 'NA',
        column: normalizeColumnId(task.column),
        dueDate: task.dueDate ?? ''
      })),
    [normalizeColumnId, props.tasks]
  );

  const [tasksState, setTasksState] = useState(initialTasks);
  const [addingColumn, setAddingColumn] = useState<string | null>(null);
  const [newTitle, setNewTitle] = useState('');
  const [newPriority, setNewPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const createClientIdRef = useRef<string | null>(null);
  const processedStreamCountRef = useRef(0);
  const initializedFromPropsRef = useRef(false);

  useEffect(() => {
    if (initializedFromPropsRef.current) return;
    setTasksState(initialTasks);
    initializedFromPropsRef.current = true;
  }, [initialTasks]);

  useEffect(() => {
    if (taskChanged.all.length <= processedStreamCountRef.current) return;
    const nextEvents = taskChanged.all.slice(processedStreamCountRef.current);
    processedStreamCountRef.current = taskChanged.all.length;

    setTasksState((prev) => {
      let next = prev;

      for (const event of nextEvents) {
        if (!event?.task?.id) continue;
        const eventTaskId = event.task.id;

        if (event.action === 'delete') {
          next = next.filter((t) => t.id !== eventTaskId);
          continue;
        }

        const taskPatch: Partial<(typeof prev)[number]> & { id: string } = { id: eventTaskId };
        if (event.task.title !== undefined) taskPatch.title = event.task.title || 'Untitled task';
        if (event.task.priority !== undefined) taskPatch.priority = event.task.priority;
        if (event.task.assignee !== undefined) taskPatch.assignee = event.task.assignee || 'NA';
        if (event.task.dueDate !== undefined) taskPatch.dueDate = event.task.dueDate || '';
        if (event.task.column !== undefined) taskPatch.column = normalizeColumnId(event.task.column);

        const existingIdx = next.findIndex((t) => t.id === eventTaskId);

        if (event.action === 'create') {
          const duplicateIdx = next.findIndex(
            (t) =>
              t.id !== eventTaskId &&
              t.title === (taskPatch.title ?? 'Untitled task') &&
              t.priority === (taskPatch.priority ?? 'low') &&
              t.assignee === (taskPatch.assignee ?? 'NA') &&
              t.column === (taskPatch.column ?? fallbackColumnId) &&
              t.dueDate === (taskPatch.dueDate ?? '')
          );

          if (duplicateIdx !== -1) {
            const merged = { ...next[duplicateIdx], ...taskPatch, id: eventTaskId };
            next = next.filter((t, i) => i !== duplicateIdx).concat(merged);
            continue;
          }

          if (createClientIdRef.current) {
            const optimisticIdx = next.findIndex((t) => t.id === createClientIdRef.current);
            if (optimisticIdx !== -1 && existingIdx === -1) {
              const replaced = [...next];
              replaced[optimisticIdx] = { ...replaced[optimisticIdx], ...taskPatch, id: eventTaskId };
              createClientIdRef.current = null;
              next = replaced;
              continue;
            }
          }
        }

        if (existingIdx === -1) {
          if (event.action !== 'create') continue;
          next = [
            {
              id: taskPatch.id,
              title: taskPatch.title ?? 'Untitled task',
              priority: taskPatch.priority ?? 'low',
              assignee: taskPatch.assignee ?? 'NA',
              column: taskPatch.column ?? fallbackColumnId,
              dueDate: taskPatch.dueDate ?? ''
            },
            ...next
          ];
          continue;
        }

        const updated = [...next];
        updated[existingIdx] = { ...updated[existingIdx], ...taskPatch, column: normalizeColumnId(taskPatch.column ?? updated[existingIdx].column) };
        next = updated;
      }

      return next;
    });
  }, [fallbackColumnId, normalizeColumnId, taskChanged.all]);
  const totalTasks = tasksState.length;
  const doneColumnId = useMemo(
    () => columns.find((c) => c.name.toLowerCase() === 'done')?.id ?? columns[columns.length - 1]?.id ?? fallbackColumnId,
    [columns, fallbackColumnId]
  );
  const completedTasks = tasksState.filter((t) => t.column === doneColumnId).length;

  const priorityVariant = useCallback((priority: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const moveTask = useCallback(
    (taskId: string, columnId: string) => {
      const nextColumn = normalizeColumnId(columnId);
      setTasksState((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: nextColumn } : t)));
      const task = tasksState.find((t) => t.id === taskId);
      taskUpdate({
        action: 'move',
        taskId,
        data: {
          column: nextColumn,
          title: task?.title ?? 'Untitled task',
          priority: task?.priority ?? 'low',
          assignee: task?.assignee ?? 'NA',
          dueDate: task?.dueDate ?? ''
        } as { column: string }
      });
    },
    [normalizeColumnId, taskUpdate, tasksState]
  );

  const createTask = useCallback(
    (targetColumnId?: string) => {
      if (!newTitle.trim()) return;
      const id = `task-${Date.now()}`;
      const created = {
        id,
        title: newTitle.trim(),
        priority: newPriority,
        assignee: 'NA',
        column: normalizeColumnId(targetColumnId ?? addingColumn ?? 'todo'),
        dueDate: ''
      };
      createClientIdRef.current = id;
      setTasksState((prev) => [created, ...prev]);
      taskUpdate({
        action: 'create',
        taskId: id,
        data: {
          column: created.column,
          title: created.title,
          priority: created.priority,
          assignee: created.assignee,
          dueDate: created.dueDate
        } as { column: string }
      });
      setNewTitle('');
      setNewPriority('medium');
      setAddingColumn(null);
    },
    [addingColumn, newPriority, newTitle, normalizeColumnId, taskUpdate]
  );

  const startEdit = useCallback((taskId: string, title: string) => {
    setEditingTaskId(taskId);
    setEditingTitle(title);
  }, []);

  const saveEdit = useCallback(
    (taskId: string, columnId: string) => {
      if (!editingTitle.trim()) return;
      const nextColumn = normalizeColumnId(columnId);
      setTasksState((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: editingTitle.trim(), column: nextColumn } : t)));
      const task = tasksState.find((t) => t.id === taskId);
      taskUpdate({
        action: 'edit',
        taskId,
        data: {
          column: nextColumn,
          title: editingTitle.trim(),
          priority: task?.priority ?? 'low',
          assignee: task?.assignee ?? 'NA',
          dueDate: task?.dueDate ?? ''
        } as { column: string }
      });
      setEditingTaskId(null);
      setEditingTitle('');
    },
    [editingTitle, normalizeColumnId, taskUpdate, tasksState]
  );

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Row justify="between" align="center">
            <Heading level={3}>Team Task Board</Heading>
            <Row gap="var(--ggui-spacing-4)">
              <Badge variant="info">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedTasks}</Badge>
            </Row>
          </Row>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Live updates received: {taskChanged.all.length}
          </Text>
        </Card>

        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
          {columns.map((column) => {
            const columnTasks = tasksState.filter((t) => normalizeColumnId(t.column) === column.id);
            return (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                border
                shadow="sm"
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={5}>{column.name}</Heading>
                    <Badge variant="default">{columnTasks.length}</Badge>
                  </Row>

                  {columnTasks.length === 0 ? (
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      No tasks yet.
                    </Text>
                  ) : (
                    <Stack gap="var(--ggui-spacing-3)">
                      {columnTasks.map((task) => (
                        <Card key={task.id} padding="var(--ggui-spacing-3)" border shadow="none">
                          <Stack gap="var(--ggui-spacing-2)">
                            {editingTaskId === task.id ? (
                              <Row gap="var(--ggui-spacing-2)">
                                <Input
                                  label="Edit task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  placeholder="Task title"
                                />
                                <Button
                                  size="sm"
                                  onClick={() => saveEdit(task.id, task.column)}
                                >
                                  Save
                                </Button>
                              </Row>
                            ) : (
                              <Row justify="between" align="center">
                                <Text
                                  as={Clickable}
                                  onDoubleClick={() => startEdit(task.id, task.title)}
                                  variant="label"
                                >
                                  {task.title}
                                </Text>
                                <Button size="sm" variant="ghost" onClick={() => startEdit(task.id, task.title)}>
                                  Edit
                                </Button>
                              </Row>
                            )}

                            <Row gap="var(--ggui-spacing-2)" align="center">
                              <Badge variant={priorityVariant(task.priority)}>{task.priority}</Badge>
                              <Avatar name={task.assignee} size="sm" />
                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  Due: {task.dueDate}
                                </Text>
                              ) : (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  No due date
                                </Text>
                              )}
                            </Row>

                            <Select
                              label="Move task"
                              value={normalizeColumnId(task.column)}
                              onChange={(value) => moveTask(task.id, value)}
                              options={columns.map((c) => ({ value: c.id, label: c.id === normalizeColumnId(task.column) ? `Keep in ${c.name}` : `Move to ${c.name}` }))}
                              placeholder="Select column"
                            />
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  )}

                  {addingColumn === column.id ? (
                    <Card padding="var(--ggui-spacing-3)" border shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTitle}
                          onChange={setNewTitle}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newPriority}
                          onChange={(value) => setNewPriority(value as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' }
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button size="sm" onClick={() => createTask(column.id)}>
                            Create
                          </Button>
                          <Button size="sm" variant="ghost" onClick={() => setAddingColumn(null)}>
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="outline" onClick={() => setAddingColumn(column.id)} fullWidth>
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Stack>
      </Stack>
    </Container>

  );
}

