}




const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-error-200, #fecaca)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'transition-metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'post-transition-metal': 'var(--ggui-color-info-200, #a5f3fc)',
  metalloid: 'var(--ggui-color-success-200, #bbf7d0)',
  nonmetal: 'var(--ggui-color-primary-100, #e0f2fe)',
  halogen: 'var(--ggui-color-warning-100, #fef3c7)',
  'noble-gas': 'var(--ggui-color-success-100, #dcfce7)',
  lanthanide: 'var(--ggui-color-primary-50, #f0f9ff)',
  actinide: 'var(--ggui-color-error-100, #fee2e2)',
  unknown: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
};

const normalizeCategory = (category?: string): string => {
  if (!category) return 'unknown';
  return category.trim().toLowerCase().replace(/[\s_]+/g, '-');
};

const getCategoryColor = (category?: string): string => {
  const normalized = normalizeCategory(category);
  return CATEGORY_COLORS[normalized] || CATEGORY_COLORS.unknown;
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [query, setQuery] = useState<string>('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][number] | null>(null);

  const elements = props.elements || [];

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => set.add(normalizeCategory(el.category)));
    return Array.from(set).sort();
  }, [elements]);

  useEffect(() => {
    if (!selectedElement) return;
    const exists = elements.some((el) => el.atomicNumber === selectedElement.atomicNumber);
    if (!exists) setSelectedElement(null);
  }, [elements, selectedElement]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={2}>Interactive Periodic Table</Heading>

        <Input
          label="Search elements by name or symbol"
