            >
              <Box
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                  gap: 'var(--ggui-spacing-2)',
                }}
              >
                {filteredElements.map((el) => (
                  <Card
                    key={el.atomicNumber || `${el.symbol}-${el.name}`}
                    as={Clickable}
                    onClick={() => setSelectedElement(el)}
                    padding="var(--ggui-spacing-2)"
                    radius="md"
                    border
                    shadow="none"
                    hoverStyle={{ opacity: 0.9 }}
                    style={{
                      gridColumn: el.col || 'auto',
                      gridRow: el.row || 'auto',
                      minHeight: '72px',
                      background: getCategoryColor(el.category),
                      borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                    }}
                  >
                    <Box style={{ position: 'relative', minHeight: '56px' }}>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-onSurfaceVariant, #52525b)"
                        style={{ position: 'absolute', top: 0, left: 0 }}
                      >
                        {el.atomicNumber ?? '—'}
                      </Text>
                      <Box
                        style={{
                          height: '100%',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                        }}
                      >
                        <Text size="xl" weight="bold" align="center">
                          {el.symbol || '—'}
                        </Text>
                      </Box>
                    </Box>
                  </Card>
                ))}
              </Box>
            </Box>

            {filteredElements.length === 0 && (
              <Alert variant="info" title="No matches">
                No elements match your search query.
              </Alert>
            )}

            <Card padding="var(--ggui-spacing-4)" radius="lg" border shadow="sm">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={4}>Element Details</Heading>
                {selectedElement ? (
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text><Text is="span" weight="semibold">Name: </Text>{selectedElement.name || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Symbol: </Text>{selectedElement.symbol || '—'}</Text>
                    <Text><Text is="span" weight="semibold">Atomic Number: </Text>{selectedElement.atomicNumber ?? '—'}</Text>
                    <Text><Text is="span" weight="semibold">Atomic Weight: </Text>{selectedElement.atomicWeight ?? '—'}</Text>
                    <Text><Text is="span" weight="semibold">Category: </Text>{selectedElement.category || 'unknown'}</Text>
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Select an element from the table to view details.
                  </Text>
                )}
