interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState<string>('description');
  const stock = props.product.stock ?? 0;
  const maxQuantity = stock > 0 ? stock : 1;
  const [quantity, setQuantity] = useState<number>(1);

  useEffect(() => {
    setQuantity(1);
  }, [props.product.id]);

  const clampedRating = Math.max(0, Math.min(5, Math.round(props.product.rating ?? 0)));
  const formattedPrice = useMemo(() => {
    const price = props.product.price ?? 0;
    const currency = props.product.currency ?? 'USD';
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency }).format(price);
    } catch {
      return `${currency} ${price.toFixed(2)}`;
    }
  }, [props.product.price, props.product.currency]);

  const specifications = Array.isArray(props.product.specifications) ? props.product.specifications : [];
  const reviews = Array.isArray(props.product.reviews) ? props.product.reviews : [];
  const isOutOfStock = stock <= 0;
  const isLowStock = stock <= 5;

  const decrementQuantity = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const incrementQuantity = useCallback(() => {
    setQuantity((prev) => Math.min(maxQuantity, prev + 1));
  }, [maxQuantity]);

  const handleAddToCart = useCallback(() => {
    if (isOutOfStock || !props.product.id) return;
    addToCart({ productId: props.product.id, quantity });
  }, [addToCart, isOutOfStock, props.product.id, quantity]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack direction="vertical" gap="var(--ggui-spacing-6)">
            <Box
              padding="var(--ggui-spacing-12)"
              background="var(--ggui-color-primary-50, #f0f9ff)"
              borderRadius="var(--ggui-shape-radius-lg)"
            >
              <Text
                align="center"
                color="var(--ggui-color-primary-700, #0369a1)"
                weight="semibold"
              >
                {props.product.name ?? 'Unnamed Product'}
              </Text>
            </Box>

            <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '260px' }}>
              <Heading level={2}>{props.product.name ?? 'Unnamed Product'}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-primary-700, #0369a1)" weight="bold">
                {formattedPrice}
              </Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                {Array.from({ length: 5 }).map((_, index) => (
                  <Text
                    key={`star-${index}`}
                    color={index < clampedRating ? 'var(--ggui-color-warning, #d97706)' : 'var(--ggui-color-outline, #d4d4d8)'}
                    size="xl"
                    is="span"
                  >
                    ★
                  </Text>
                ))}
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  ({props.product.reviewCount ?? reviews.length})
                </Text>
              </Row>
              <Badge variant={isLowStock ? 'warning' : 'success'} size="md">
                {isLowStock ? 'Low Stock' : 'In Stock'}
              </Badge>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Stock: {stock}
              </Text>
            </Stack>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Text color="var(--ggui-color-onSurface, #18181b)">
                    {props.product.description ?? 'No description available.'}
                  </Text>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: specifications.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'key', header: 'Property' },
                      { key: 'value', header: 'Value' },
                    ]}
                    data={specifications.map((item, idx) => {
                      const record = (item ?? {}) as Record<string, unknown>;
                      return {
                        id: `spec-${idx}`,
                        key: String(record.key ?? record.name ?? `Spec ${idx + 1}`),
                        value: String(record.value ?? record.detail ?? ''),
                      };
                    })}
                  />
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications provided.</Text>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: reviews.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-4)">
                    {reviews.map((review, idx) => {
                      const r = (review ?? {}) as Record<string, unknown>;
                      const reviewRating = Math.max(0, Math.min(5, Math.round(Number(r.rating ?? 0))));
                      return (
                        <Card key={`review-${idx}`} padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="center">
                              <Text weight="semibold">{String(r.author ?? 'Anonymous')}</Text>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                {String(r.date ?? '')}
                              </Text>
                            </Row>
                            <Row gap="var(--ggui-spacing-1)">
                              {Array.from({ length: 5 }).map((__, i) => (
                                <Text
                                  key={`review-star-${idx}-${i}`}
                                  color={i < reviewRating ? 'var(--ggui-color-warning, #d97706)' : 'var(--ggui-color-outline, #d4d4d8)'}
                                  is="span"
                                >
                                  ★
                                </Text>
                              ))}
                            </Row>
                            <Text>{String(r.text ?? '')}</Text>
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>
                ) : (
                  <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet.</Text>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center" wrap>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Button variant="outline" onClick={decrementQuantity} disabled={quantity <= 1 || isOutOfStock}>
                -
              </Button>
              <Text weight="medium">Quantity: {quantity}</Text>
              <Button variant="outline" onClick={incrementQuantity} disabled={quantity >= maxQuantity || isOutOfStock}>
                +
              </Button>
            </Row>
            <Button variant="primary" onClick={handleAddToCart} disabled={isOutOfStock || !props.product.id}>
              Add to Cart
            </Button>
            {isOutOfStock && <Badge variant="error">Out of Stock</Badge>}
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

