import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState<string>('');
  const [activeTypingSender, setActiveTypingSender] = useState<string>('');
  const messagesScrollRef = useRef<HTMLDivElement | null>(null);
  const [forceScrollToBottom, setForceScrollToBottom] = useState<boolean>(false);

  useEffect(() => {
    if (!props.messages?.length) return;
    setAllMessages((prev) => {
      const existingKeys = new Set(
        prev.map((m) => `${m.sender ?? 'Unknown'}|${m.text ?? ''}|${m.timestamp ?? ''}`),
      );
      const merged = [...prev];
      for (const msg of props.messages) {
        const key = `${msg.sender ?? 'Unknown'}|${msg.text ?? ''}|${msg.timestamp ?? ''}`;
        if (!existingKeys.has(key)) {
          merged.push(msg);
          existingKeys.add(key);
        }
      }
      return merged;
    });
  }, [props.messages]);

  useEffect(() => {
    const incoming = message.latest;
    if (!incoming || incoming.sender === props.currentUser) return;
    setAllMessages((prev) => [...prev, incoming]);
  }, [message.latest, props.currentUser]);

  useEffect(() => {
    const latestTyping = typing.latest;
    if (!latestTyping) return;
    if (latestTyping.active && latestTyping.sender && latestTyping.sender !== props.currentUser) {
      setActiveTypingSender(latestTyping.sender);
      return;
    }
    if (!latestTyping.active) {
      setActiveTypingSender('');
    }
  }, [typing.latest, props.currentUser]);

  useEffect(() => {
    const container = messagesScrollRef.current;
    if (!container) return;
    const distanceFromBottom = container.scrollHeight - container.scrollTop - container.clientHeight;
    const isNearBottom = distanceFromBottom <= 80;
    if (isNearBottom || forceScrollToBottom) {
      container.scrollTo({ top: container.scrollHeight, behavior: forceScrollToBottom ? 'smooth' : 'auto' });
      if (forceScrollToBottom) {
        setForceScrollToBottom(false);
      }
    }
  }, [allMessages.length, forceScrollToBottom]);

  const groupedMessages = useMemo(() => {
    return (allMessages ?? []).reduce<Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }>>(
      (acc, item) => {
        const sender = item?.sender ?? 'Unknown';
        const lastGroup = acc[acc.length - 1];
        if (!lastGroup || (lastGroup.sender ?? 'Unknown') !== sender) {
          acc.push({ sender, items: [item] });
        } else {
          lastGroup.items.push(item);
        }
        return acc;
      },
      [],
    );
  }, [allMessages]);

  const formatTimestamp = useCallback((value?: string) => {
    if (!value) return '';
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return value;
    return parsed.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const handleSend = useCallback(() => {
    const text = draft.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text, timestamp });
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text, timestamp }]);
    setForceScrollToBottom(true);
    setDraft('');
  }, [draft, sendMessage, props.currentUser]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-6)"
        radius="lg"
        shadow="sm"
        border
      >
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{props.title}</Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant="primary">{props.participantCount} participants</Badge>
              {activeTypingSender ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {activeTypingSender} is typing...
                </Text>
              ) : null}
            </Row>
          </Row>

          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Stack gap="var(--ggui-spacing-2)">
              {groupedMessages.length === 0 ? (
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">No messages yet</Text>
              ) : null}

              <Box
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                padding="var(--ggui-spacing-2)"
              >
                <div
                  ref={messagesScrollRef}
                  style={{
                    maxHeight: '60vh',
                    overflowY: 'auto',
                    padding: 'var(--ggui-spacing-2)',
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    {groupedMessages.map((group, groupIndex) => {
                      const isOwnGroup = (group.sender ?? '') === props.currentUser;
                      return (
                        <Stack
                          key={`${group.sender ?? 'unknown'}-${groupIndex}` }
                          align={isOwnGroup ? 'end' : 'start'}
                          gap="var(--ggui-spacing-1)"
                        >
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            {group.sender ?? 'Unknown'}
                          </Text>
                          {group.items.map((msg, msgIndex) => (
                            <Box
                              key={`${groupIndex}-${msgIndex}-${msg.timestamp ?? 't'}` }
                              padding="var(--ggui-spacing-2)"
                              background={
                                isOwnGroup
                                  ? 'var(--ggui-color-primary-600, #0284c7)'
                                  : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                              }
                              borderRadius="var(--ggui-shape-radius-md, 8px)"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  color={
                                    isOwnGroup
                                      ? 'var(--ggui-color-surface, #fafafa)'
                                      : 'var(--ggui-color-onSurface, #18181b)'
                                  }
                                >
                                  {msg.text ?? ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={
                                    isOwnGroup
                                      ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                      : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                                  }
                                >
                                  {formatTimestamp(msg.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      );
                    })}
                  </Stack>
                </div>
              </Box>

            </Stack>
          </Box>

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box padding="0" background="var(--ggui-color-surface, #fafafa)" borderRadius="var(--ggui-shape-radius-md, 8px)">
              <Input
                label="Message"
                placeholder="Type your message"
                value={draft}
                onChange={setDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button variant="primary" onClick={handleSend} disabled={!draft.trim()}>
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

