import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocks, setStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, boolean>>({});

  useEffect(() => {
    setStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest?.symbol) return;
    const incoming = priceUpdate.latest;
    const symbolKey = incoming.symbol ?? '';

    setStocks((prev) =>
      (prev ?? []).map((stock) =>
        stock.symbol === incoming.symbol
          ? {
              ...stock,
              price: incoming.price ?? stock.price,
              change: incoming.change ?? stock.change,
              changePercent: incoming.changePercent ?? stock.changePercent,
            }
          : stock,
      ),
    );

    setFlashMap((prev) => ({ ...prev, [symbolKey]: true }));
    setLastUpdated(new Date());
    const timeout = setTimeout(() => {
      setFlashMap((prev) => ({ ...prev, [symbolKey]: false }));
    }, 600);

    return () => clearTimeout(timeout);
  }, [priceUpdate.latest]);

  const marketStatusLabel = marketStatus.latest?.status ?? 'open';
  const marketTimestamp = marketStatus.latest?.timestamp;

  const statusVariant =
    marketStatusLabel === 'open'
      ? 'success'
      : marketStatusLabel === 'closed'
        ? 'error'
        : 'warning';

  return (
    <Box background="var(--ggui-color-surface, #fafafa)">
      <Container
        maxWidth="xl"
        padding="var(--ggui-spacing-6)"
      >
      <Stack gap="var(--ggui-spacing-6)">
        <Card
          padding="var(--ggui-spacing-6)"
          border
          shadow="sm"
          radius="lg"
        >
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Market Watch
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {lastUpdated.toLocaleTimeString()}
              </Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Current Time: {now.toLocaleTimeString()}
              </Text>
            </Stack>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Badge variant={statusVariant}>
                {marketStatusLabel}
              </Badge>
              {marketTimestamp ? (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {marketTimestamp}
                </Text>
              ) : null}
            </Stack>
          </Row>
        </Card>

        {(stocks ?? []).length === 0 ? (
          <Card padding="var(--ggui-spacing-6)" border radius="lg">
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              No stocks available.
            </Text>
          </Card>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {(stocks ?? []).map((stock, index) => {
              const symbol = stock.symbol ?? `stock-${index}`;
              const change = stock.change ?? 0;
              const changePercent = stock.changePercent ?? 0;
              const isPositive = change >= 0;
              const accentColor = isPositive
                ? 'var(--ggui-color-success, #16a34a)'
                : 'var(--ggui-color-error, #dc2626)';
              const arrow = isPositive ? '▲' : '▼';

              return (
                <Card
                  key={symbol}
                  padding="var(--ggui-spacing-6)"
                  border
                  radius="lg"
                  shadow="sm"
                >
                  <Box
                    padding="var(--ggui-spacing-1)"
                    borderRadius="var(--ggui-shape-radius-md, 8px)"
                    background={flashMap[symbol] ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'transparent'}
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {stock.symbol ?? '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                      <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>
                      <Row justify="between" align="center">
                        <Text weight="medium" color={accentColor}>
                          {change >= 0 ? '+' : ''}{change.toFixed(2)}
                        </Text>
                        <Text weight="medium" color={accentColor}>
                          {arrow} {changePercent >= 0 ? '+' : ''}{changePercent.toFixed(2)}%
                        </Text>
                      </Row>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
      </Container>
    </Box>
  );
}

