// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  const defaultAvatars = ['😀', '🚀', '🎨', '🧠'];
  const safeAvatarOptions = props.avatarOptions.length >= 4 ? props.avatarOptions.slice(0, 4) : defaultAvatars;
  const safeRoleOptions = props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other'];

  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name ?? '');
  const [email, setEmail] = useState(props.initialProfile.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar ?? safeAvatarOptions[0] ?? defaultAvatars[0]);
  const [role, setRole] = useState(props.initialProfile.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme ?? 'light');

  useEffect(() => {
    setName(props.initialProfile.name ?? '');
    setEmail(props.initialProfile.email ?? '');
    setAvatar(props.initialProfile.avatar ?? safeAvatarOptions[0] ?? defaultAvatars[0]);
    setRole(props.initialProfile.role ?? '');
    setEmailNotifications(props.initialProfile.emailNotifications ?? true);
    setTheme(props.initialProfile.theme ?? 'light');
  }, [props.initialProfile, safeAvatarOptions]);

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = emailRegex.test(email.trim());
  const step1Valid = name.trim().length > 0 && email.trim().length > 0 && isEmailValid && avatar.trim().length > 0;
  const step2Valid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canGoNext = step === 1 ? step1Valid : step === 2 ? step2Valid : true;
  const progressValue = (step / 3) * 100;

  const nextStep = useCallback(() => {
    if (step < 3 && canGoNext) {
      setStep((s) => s + 1);
    }
  }, [step, canGoNext]);

  const prevStep = useCallback(() => {
    if (step > 1) {
      setStep((s) => s - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    if (!step1Valid || !step2Valid) return;
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [step1Valid, step2Valid, complete, name, email, avatar, role, emailNotifications, theme]);

  const stepTitle = useMemo(() => {
    if (step === 1) return 'Profile Setup';
    if (step === 2) return 'Preferences';
    return 'Review & Confirm';
  }, [step]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} / 3</Badge>
            </Row>
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">{stepTitle}</Text>
            <Progress value={progressValue} max={100} size="md" />
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="sm"
          border
        >
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={email.trim().length === 0 ? 'Email is required' : !isEmailValid ? 'Please enter a valid email format' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose Avatar</Text>
                  <Row gap="var(--ggui-spacing-2)">
                    {safeAvatarOptions.slice(0, 4).map((emoji) => (
                      <Card
                        key={emoji}
                        as={Clickable}
                        onClick={() => setAvatar(emoji)}
                        padding="var(--ggui-spacing-2)"
                        border
                        shadow="none"
                        radius="md"
                        style={{
                          minWidth: '56px',
                          textAlign: 'center',
                          borderColor: avatar === emoji ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                          background: avatar === emoji ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surface, #fafafa)',
                        }}
                      >
                        <Text size="2xl" align="center">{emoji}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  options={safeRoleOptions.map((option) => ({ value: option, label: option }))}
                  placeholder="Select your role"
                  required
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review your setup</Heading>
                <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                  </Stack>
                </Card>
                <Alert variant="info" title="Confirm details">
                  Please confirm the above information, then complete your setup.
                </Alert>
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="ghost" onClick={prevStep} disabled={step === 1}>
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {step < 3 ? (
              <Button variant="primary" onClick={nextStep} disabled={!canGoNext}>
                Next
              </Button>
            ) : (
              <>
                <Button variant="outline" onClick={prevStep}>
                  Go Back
                </Button>
                <Button variant="primary" onClick={handleComplete} disabled={!step1Valid || !step2Valid}>
                  Complete Setup
                </Button>
              </>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>
  );
}
